
.character-detail {
  display: flex;
  flex-direction: column;
  gap: 32px;
  padding-bottom: 80px;
  width: 100%;
  max-width: 1400px;
  margin-inline: auto;
  box-sizing: border-box;
}

.edit-mode-bar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 16px;
  padding: 8px 0;
  border-bottom: 1px solid rgba(255, 255, 255, 0.1);

  .btn-complete {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    padding: 8px 16px;
    border-radius: 8px;
    border: none;
    cursor: pointer;
    font-size: 14px;
    font-weight: 500;
    background: #22c55e;
    color: #fff;

    &:hover { background: #16a34a; }
  }

  .btn-cancel {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    padding: 8px 16px;
    border-radius: 8px;
    border: none;
    cursor: pointer;
    font-size: 14px;
    font-weight: 500;
    background: #ef4444;
    color: #fff;

    &:hover { background: #dc2626; }
  }
}

.back-btn {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 14px;
  color: #a1a1aa;
  background: transparent;
  border: none;
  cursor: pointer;
  transition: color 0.2s;
  width: fit-content;

  &:hover {
    color: #fff;
  }
}

:global(.light) .back-btn:hover {
  color: #18181b;
}

.profile-header {
  display: flex;
  flex-direction: row;
  align-items: flex-start;
  gap: 20px;

  @media (max-width: 639px) {
    flex-direction: column;
    align-items: center;
    text-align: center;

    .profile-main {
      align-items: center;
    }

    .profile-info .name-row {
      justify-content: center;
    }

    .header-actions {
      width: 100%;
      justify-content: center;
      flex-wrap: wrap;
    }
  }

  .avatar-edit {
    width: 128px;
    height: 128px;
    flex-shrink: 0;
    border-radius: 16px;
    display: flex;
    align-items: center;
    justify-content: center;
    position: relative;
    overflow: hidden;
    cursor: pointer;
    border: 1px solid rgba(255, 255, 255, 0.1);
    background: rgba(255, 255, 255, 0.02);

    .avatar-face {
      width: 100%;
      height: 100%;
      object-fit: cover;
    }

    i {
      font-size: 48px;
      color: #52525b;
      transition: transform 0.5s ease;
    }

    &:hover i {
      transform: scale(1.1);
    }

    .edit-overlay {
      position: absolute;
      inset: 0;
      display: flex;
      align-items: center;
      justify-content: center;
      background: rgba(0, 0, 0, 0.5);
      opacity: 0;
      transition: opacity 0.3s;

      i {
        font-size: 20px;
        color: #fff;
        transform: none;
      }
    }

    &:hover .edit-overlay {
      opacity: 1;
    }
  }

  // 始终纵向：姓名 → 元数据 → 按钮行，避免大屏下与按钮并排导致文字区被 flex 压成「一字一行」
  .profile-main {
    flex: 1;
    min-width: 0;
    display: flex;
    flex-direction: column;
    align-items: flex-start;
    align-self: stretch;
    gap: 14px;
    padding-top: 4px;
  }

  .profile-info {
    width: 100%;
    min-width: 0;

    .name-row {
      display: flex;
      align-items: center;
      gap: 12px;
      margin-bottom: 8px;

      h2 {
        font-size: clamp(1.5rem, 2.5vw, 2.25rem);
        font-weight: 700;
        letter-spacing: 0.02em;
        color: #fff;
        word-break: keep-all;
        overflow-wrap: break-word;
        line-height: 1.2;
        font-family: ui-sans-serif, system-ui, 'Segoe UI', 'PingFang SC', 'Microsoft YaHei', sans-serif;
      }
    }

    .meta {
      font-size: 14px;
      color: #a1a1aa;
      font-family: ui-monospace, 'Cascadia Code', 'Segoe UI Mono', monospace;
      white-space: normal;
      word-break: normal;
      overflow-wrap: anywhere;
      line-height: 1.5;
    }
  }
}

@media (min-width: 1100px) {
  .profile-header .avatar-edit {
    width: 144px;
    height: 144px;
    border-radius: 18px;
  }
}

:global(.light) .profile-header {
  .avatar-edit {
    border-color: rgba(0, 0, 0, 0.1);
    background: #f4f4f5;
  }

  .profile-info .name-row h2 {
    color: #18181b;
  }
}

.edit-btn {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 8px 16px;
  border-radius: 8px;
  font-size: 14px;
  font-weight: 500;
  cursor: pointer;
  transition: all 0.2s;
  border: none;
  background: rgba(255, 255, 255, 0.05);
  color: #e4e4e7;
  white-space: nowrap;

  &:hover {
    background: rgba(255, 255, 255, 0.1);
  }
}

:global(.light) .edit-btn {
  background: rgba(0, 0, 0, 0.05);
  color: #27272a;

  &:hover {
    background: rgba(0, 0, 0, 0.1);
  }
}

.header-actions {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  flex-shrink: 0;
  align-self: flex-start;
}

.delete-btn {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 8px 16px;
  border-radius: 8px;
  font-size: 14px;
  font-weight: 500;
  cursor: pointer;
  transition: all 0.2s;
  border: none;
  background: rgba(239, 68, 68, 0.1);
  color: #ef4444;
  white-space: nowrap;

  &:hover {
    background: rgba(239, 68, 68, 0.2);
  }
}

:global(.light) .delete-btn {
  background: rgba(239, 68, 68, 0.08);
  color: #dc2626;

  &:hover {
    background: rgba(239, 68, 68, 0.15);
  }
}

.detail-grid {
  display: grid;
  grid-template-columns: 1fr;
  gap: 24px;

  @media (min-width: 768px) {
    grid-template-columns: repeat(2, minmax(0, 1fr));
    gap: 24px;
  }

  @media (min-width: 1280px) {
    grid-template-columns: repeat(3, minmax(0, 1fr));
    gap: 28px;
  }

  > .rules-card {
    @media (min-width: 768px) {
      grid-column: 1 / -1;
    }
  }

  > .identity-tags-card {
    @media (min-width: 1280px) {
      grid-column: span 2;
    }
  }
}

// 与是否挂上 .cyber-card 无关：保证深色/赛博下标题行与「编辑」同一套 flex 排版
.detail-card .card-title {
  display: flex;
  align-items: center;
  gap: 12px;
  padding-bottom: 16px;
  border-bottom: 1px solid rgba(255, 255, 255, 0.1);

  > i {
    flex-shrink: 0;
    font-size: 20px;
    color: #d4d4d8;
  }

  > h3 {
    flex: 1;
    min-width: 0;
    font-size: 18px;
    font-weight: 500;
    color: #f4f4f5;
  }

  .edit-mini-btn {
    flex-shrink: 0;
    align-self: center;
    padding: 6px 4px;
    font-size: 15px;
    font-weight: 600;
    line-height: 1.2;
    color: #4ade80;
    background: transparent;
    border: none;
    cursor: pointer;
    transition: color 0.2s, filter 0.2s;
    white-space: nowrap;

    &:hover {
      color: #86efac;
    }

    &:active {
      filter: brightness(1.08);
    }
  }
}

.detail-card:not(.cyber-card) {
  padding: 24px;
  border-radius: 16px;
  border: 1px solid rgba(255, 255, 255, 0.1);
  background: rgba(255, 255, 255, 0.02);
  display: flex;
  flex-direction: column;
  gap: 24px;
}

.detail-card.cyber-card {
  display: flex;
  flex-direction: column;
  gap: 24px;
  padding: 24px;
  border-radius: 14px;
}

:global(.light) .detail-card:not(.cyber-card) {
  border-color: rgba(0, 0, 0, 0.1);
  background: #fff;
}

:global(.light) .detail-card .card-title {
  border-bottom-color: rgba(0, 0, 0, 0.1);

  > i {
    color: #52525b;
  }

  > h3 {
    color: #18181b;
  }

  .edit-mini-btn {
    color: #16a34a;

    &:hover {
      color: #15803d;
    }
  }
}

.stats-list {
  display: flex;
  flex-direction: column;
  gap: 16px;

  &.edit-stats .stat-row.edit {
    display: flex;
    justify-content: space-between;
    align-items: center;
    gap: 12px;

    .label {
      font-size: 14px;
      color: #71717a;
      flex-shrink: 0;
    }

    .edit-value {
      flex: 1;
      max-width: 180px;
      padding: 6px 10px;
      border-radius: 6px;
      font-size: 14px;
      border: 1px solid rgba(255, 255, 255, 0.2);
      background: rgba(255, 255, 255, 0.05);
      color: #fff;
      outline: none;
    }
  }
}

:global(.light) .stats-list.edit-stats .stat-row.edit .edit-value {
  border-color: rgba(0, 0, 0, 0.15);
  background: #fff;
  color: #18181b;
}

.edit-name-input {
  font-size: 36px;
  font-weight: 700;
  padding: 4px 8px;
  border-radius: 8px;
  border: 1px solid rgba(255, 255, 255, 0.2);
  background: rgba(255, 255, 255, 0.05);
  color: #fff;
  outline: none;
  width: 100%;
  max-width: 320px;
}

:global(.light) .edit-name-input {
  border-color: rgba(0, 0, 0, 0.15);
  background: #fff;
  color: #18181b;
}

.stat-bars {
  display: flex;
  flex-direction: column;
  gap: 16px;
  padding-top: 24px;
  border-top: 1px solid rgba(255, 255, 255, 0.05);
}

:global(.light) .stat-bars {
  border-color: rgba(0, 0, 0, 0.05);
}

.physiology-summary {
  margin-top: 20px;
  padding-top: 16px;
  border-top: 1px solid rgba(255, 255, 255, 0.05);

  .section-label {
    display: block;
    font-size: 12px;
    color: #71717a;
    text-transform: uppercase;
    letter-spacing: 0.1em;
    margin-bottom: 8px;
  }

  .thought-text {
    font-size: 14px;
    color: #d4d4d8;
    line-height: 1.6;
  }
}

:global(.light) .physiology-summary {
  border-color: rgba(0, 0, 0, 0.05);

  .thought-text {
    color: #3f3f46;
  }
}

.psych-content,
.fetish-content {
  display: flex;
  flex-direction: column;
  gap: 16px;
}

.thought-section {
  .section-label {
    display: block;
    font-size: 12px;
    color: #71717a;
    text-transform: uppercase;
    letter-spacing: 0.1em;
    margin-bottom: 8px;
  }

  .thought-text {
    font-size: 14px;
    color: #d4d4d8;
    font-style: italic;
    line-height: 1.6;
  }
}

:global(.light) .thought-section .thought-text {
  color: #3f3f46;
}

.traits-section,
.sensitive-section {
  .section-label {
    display: block;
    font-size: 12px;
    color: #71717a;
    text-transform: uppercase;
    letter-spacing: 0.1em;
    margin-bottom: 12px;
  }

  .badges {
    display: flex;
    flex-wrap: wrap;
    gap: 8px;
  }
}

.empty-hint {
  font-size: 14px;
  color: #71717a;
}

.rules-grid .empty-hint {
  padding: 12px 0;
}

.hidden-fetish {
  .section-label {
    display: block;
    font-size: 12px;
    color: #71717a;
    text-transform: uppercase;
    letter-spacing: 0.1em;
    margin-bottom: 8px;
  }

  p {
    font-size: 14px;
    color: #d4d4d8;
    line-height: 1.6;
  }
}

:global(.light) .hidden-fetish p {
  color: #3f3f46;
}

// 与 .cyber-card 无关：与上方 .detail-card .card-title 同一套顶栏逻辑（含窄屏防「一字一行」）
.rules-card .rules-header {
  display: flex;
  flex-direction: row;
  flex-wrap: nowrap;
  justify-content: space-between;
  align-items: center;
  gap: 12px;
  width: 100%;
  min-width: 0;
  padding-bottom: 16px;
  border-bottom: 1px solid rgba(255, 255, 255, 0.1);
  margin-bottom: 24px;

  .title-group {
    display: flex;
    flex-direction: row;
    flex-wrap: nowrap;
    align-items: center;
    gap: 12px;
    min-width: 0;
    flex: 1 1 0%;

    > i {
      flex-shrink: 0;
      font-size: 20px;
      color: #d4d4d8;
    }

    > h3 {
      flex: 1 1 0%;
      min-width: 0;
      font-size: 18px;
      font-weight: 500;
      color: #f4f4f5;
      line-height: 1.35;
      writing-mode: horizontal-tb;
      word-break: keep-all;
      overflow-wrap: break-word;
    }
  }

  .manage-btn {
    flex-shrink: 0;
    align-self: center;
    padding: 6px 4px;
    font-size: 15px;
    font-weight: 600;
    line-height: 1.2;
    color: #4ade80;
    background: transparent;
    border: none;
    cursor: pointer;
    transition: color 0.2s, filter 0.2s;
    white-space: nowrap;
    text-align: right;

    &:hover {
      color: #86efac;
    }

    &:active {
      filter: brightness(1.08);
    }
  }
}

.rules-card:not(.cyber-card) {
  padding: 24px;
  border-radius: 16px;
  border: 1px solid rgba(255, 255, 255, 0.1);
  background: rgba(255, 255, 255, 0.02);
}

.rules-card.cyber-card {
  padding: 24px;
  border-radius: 14px;
}

/* 与 .detail-card 一致：占满网格列宽，避免父级 flex/grid 下被压成 min-content 导致标题竖排 */
.rules-card {
  width: 100%;
  min-width: 0;
  box-sizing: border-box;
}

@media (max-width: 768px) {
  .rules-card .rules-header {
    flex-direction: column;
    align-items: stretch;
    flex-wrap: wrap;
    gap: 10px;

    .title-group {
      flex: none;
      width: 100%;
    }

    .manage-btn {
      align-self: flex-end;
    }
  }
}

:global(.light) .rules-card:not(.cyber-card) {
  border-color: rgba(0, 0, 0, 0.1);
  background: #fff;
}

:global(.light) .rules-card .rules-header {
  border-bottom-color: rgba(0, 0, 0, 0.1);

  .title-group {
    > i {
      color: #52525b;
    }

    > h3 {
      color: #18181b;
    }
  }

  .manage-btn {
    color: #16a34a;

    &:hover {
      color: #15803d;
    }
  }
}

.rules-grid {
  display: flex;
  flex-direction: column;
  gap: 0;
}

.personal-rule-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 10px 0;
  border-bottom: 1px solid rgba(255, 255, 255, 0.05);

  &:last-child {
    border-bottom: none;
  }

  .rule-desc {
    font-size: 13px;
    color: #a1a1aa;
    flex: 1;
    min-width: 0;
    margin-right: 12px;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
    line-height: 1.5;
  }

  .rule-actions {
    display: flex;
    gap: 4px;
    flex-shrink: 0;

    .action {
      display: flex;
      align-items: center;
      justify-content: center;
      width: 28px;
      height: 28px;
      padding: 0;
      border: none;
      border-radius: 4px;
      cursor: pointer;
      transition: all 0.2s;
      font-size: 12px;

      &.edit {
        color: #60a5fa;
        background: rgba(96, 165, 250, 0.1);

        &:hover {
          background: rgba(96, 165, 250, 0.2);
        }
      }

      &.archive {
        color: #f59e0b;
        background: rgba(245, 158, 11, 0.1);

        &:hover {
          background: rgba(245, 158, 11, 0.2);
        }
      }

      &.delete {
        color: #ef4444;
        background: rgba(239, 68, 68, 0.1);

        &:hover {
          background: rgba(239, 68, 68, 0.2);
        }
      }
    }
  }
}

:global(.light) .personal-rule-row {
  border-color: rgba(0, 0, 0, 0.05);

  .rule-desc {
    color: #71717a;
  }
}

@media (max-width: 768px) {
  .personal-rule-row {
    flex-direction: column;
    align-items: stretch;
    gap: 10px;
    padding: 12px 0;
  }

  .personal-rule-row .rule-desc {
    margin-right: 0;
    white-space: normal;
    overflow: visible;
    text-overflow: unset;
    word-break: break-word;
    overflow-wrap: anywhere;
  }

  .personal-rule-row .rule-actions {
    justify-content: flex-end;
  }
}

// 可点击的徽章样式
.clickable-badge {
  cursor: pointer;
  transition: all 0.2s;

  &:hover {
    transform: scale(1.05);
    box-shadow: 0 0 8px rgba(255, 255, 255, 0.2);
  }
}

// 详情展开面板
.detail-expand-panel {
  margin-top: 12px;
  padding: 16px;
  border-radius: 12px;
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid rgba(255, 255, 255, 0.1);
  animation: slideDown 0.2s ease-out;

  .detail-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 12px;
    padding-bottom: 8px;
    border-bottom: 1px solid rgba(255, 255, 255, 0.1);

    .detail-title {
      font-size: 16px;
      font-weight: 600;
      color: #f472b6;
    }

    .close-btn {
      display: flex;
      align-items: center;
      justify-content: center;
      width: 24px;
      height: 24px;
      border: none;
      border-radius: 50%;
      background: rgba(255, 255, 255, 0.1);
      color: #a1a1aa;
      cursor: pointer;
      transition: all 0.2s;

      &:hover {
        background: rgba(239, 68, 68, 0.3);
        color: #ef4444;
      }
    }
  }

  .detail-body {
    display: flex;
    flex-direction: column;
    gap: 12px;

    .detail-row {
      display: flex;
      flex-direction: column;
      gap: 4px;

      .detail-label {
        font-size: 11px;
        color: #71717a;
        text-transform: uppercase;
        letter-spacing: 0.05em;
      }

      .detail-value {
        font-size: 14px;
        color: #d4d4d8;
        line-height: 1.5;
      }
    }
  }
}

@keyframes slideDown {
  from {
    opacity: 0;
    transform: translateY(-10px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

// 身份标签样式
.identity-content {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.identity-tag-row {
  display: flex;
  align-items: flex-start;
  gap: 12px;
  padding: 8px 12px;
  border-radius: 8px;
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid rgba(255, 255, 255, 0.05);

  .identity-category {
    flex-shrink: 0;
    min-width: 80px;
    font-size: 12px;
    font-weight: 500;
    color: #a78bfa;
    text-transform: uppercase;
    letter-spacing: 0.05em;
  }

  .identity-value {
    font-size: 14px;
    color: #d4d4d8;
    line-height: 1.5;
  }
}

.appearance-content {
  display: flex;
  flex-direction: column;
  gap: 20px;
}

.appearance-block {
  .section-label.sub {
    display: block;
    margin-top: 12px;
    margin-bottom: 6px;
    font-size: 1.25rem;
    font-weight: 700;
    color: #f87171;
    letter-spacing: 0.02em;
  }
}

:global(.light) .appearance-block .section-label.sub {
  color: #dc2626;
}

.appearance-slots {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.appearance-slot-line {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  font-size: 14px;
  line-height: 1.5;

  .slot-name {
    flex-shrink: 0;
    min-width: 2.5em;
    color: #a78bfa;
    font-weight: 500;
  }

  .slot-text {
    color: #d4d4d8;
  }
}

.appearance-list {
  margin: 0;
  padding-left: 1.25em;
  font-size: 14px;
  color: #d4d4d8;
  line-height: 1.6;
}

.body-part-rows {
  display: flex;
  flex-direction: column;
  gap: 14px;
  margin-top: 6px;
}

.body-part-line {
  display: flex;
  flex-direction: column;
  align-items: flex-start;
  gap: 0;
  width: 100%;
  text-align: left;
  padding: 10px 14px;
  border-radius: 12px;
  border: 1px solid rgba(255, 255, 255, 0.1);
  background: rgba(255, 255, 255, 0.03);
  cursor: pointer;
  transition: border-color 0.2s, background 0.2s;
  font: inherit;
  color: inherit;

  &:hover {
    border-color: rgba(255, 255, 255, 0.16);
    background: rgba(255, 255, 255, 0.06);
  }

  &.is-expanded {
    border-color: rgba(167, 139, 250, 0.5);
    background: rgba(167, 139, 250, 0.09);
  }
}

.body-part-name {
  font-size: 14px;
  font-weight: 600;
  color: #a78bfa;
  line-height: 1.35;
}

:global(.light) {
  .appearance-slot-line .slot-text,
  .appearance-list {
    color: #3f3f46;
  }

  .body-part-line {
    border-color: rgba(0, 0, 0, 0.1);
    background: rgba(0, 0, 0, 0.02);

    &:hover {
      border-color: rgba(0, 0, 0, 0.14);
      background: rgba(0, 0, 0, 0.04);
    }

    &.is-expanded {
      border-color: rgba(124, 58, 237, 0.35);
      background: rgba(124, 58, 237, 0.06);
    }
  }

  .body-part-name {
    color: #7c3aed;
  }

  .detail-expand-panel {
    background: rgba(0, 0, 0, 0.03);
    border-color: rgba(0, 0, 0, 0.1);

    .detail-header {
      border-color: rgba(0, 0, 0, 0.1);

      .detail-title {
        color: #db2777;
      }

      .close-btn:hover {
        background: rgba(239, 68, 68, 0.15);
        color: #dc2626;
      }
    }

    .detail-body .detail-row {
      .detail-label {
        color: #71717a;
      }
      .detail-value {
        color: #3f3f46;
      }
    }
  }

  .identity-tag-row {
    background: rgba(0, 0, 0, 0.02);
    border-color: rgba(0, 0, 0, 0.08);

    .identity-category {
      color: #7c3aed;
    }

    .identity-value {
      color: #3f3f46;
    }
  }

  .clickable-badge:hover {
    box-shadow: 0 0 8px rgba(0, 0, 0, 0.15);
  }
}
