
.stat-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 4px 0;

  .label {
    font-size: 14px;
    color: #71717a;
  }

  .value {
    font-size: 14px;
    font-family: monospace;
    color: #f4f4f5;
  }
}

:global(.light) .stat-row .value {
  color: #18181b;
}
