
.world-life-panel {
  display: flex;
  flex-direction: column;
  height: 100%;
  overflow: hidden;
}

// ==================== Tabs Header ====================
.tabs-header {
  display: flex;
  gap: 8px;
  padding: 16px;
  border-bottom: 1px solid rgba(255, 255, 255, 0.06);
  flex-shrink: 0;
}

.light .tabs-header {
  border-color: rgba(0, 0, 0, 0.06);
}

.tab-btn {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 8px 16px;
  border-radius: 6px;
  font-size: 14px;
  font-weight: 500;
  cursor: pointer;
  transition: all 0.2s;
  border: none;
  background: transparent;
  color: #a1a1aa;

  i {
    font-size: 14px;
  }

  &:hover {
    background: rgba(255, 255, 255, 0.03);
    color: #e4e4e7;
  }

  &.active {
    background: rgba(59, 130, 246, 0.1);
    color: #3b82f6;
  }
}

.light .tab-btn {
  color: #71717a;

  &:hover {
    background: rgba(0, 0, 0, 0.03);
    color: #27272a;
  }

  &.active {
    background: rgba(59, 130, 246, 0.1);
    color: #2563eb;
  }
}

.badge {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 18px;
  height: 18px;
  padding: 0 6px;
  border-radius: 9px;
  background: #ef4444;
  color: white;
  font-size: 11px;
  font-weight: 600;
}

// ==================== Tab Content ====================
.tab-content {
  flex: 1;
  overflow-y: auto;
  padding: 16px;
}

// ==================== Empty State ====================
.empty-state {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 48px 24px;
  gap: 16px;
  color: #71717a;

  i {
    font-size: 48px;
    opacity: 0.3;
  }

  p {
    font-size: 16px;
    font-weight: 500;
  }

  .hint {
    font-size: 13px;
    text-align: center;
    max-width: 280px;
  }
}

.light .empty-state {
  color: #a1a1aa;
}

// ==================== Latest Card ====================
.latest-card {
  margin-bottom: 24px;
  cursor: pointer;
  transition: all 0.2s;

  &.expanded {
    .detail-content {
      display: block;
    }
  }
}

.latest-card:not(.cyber-card) {
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid rgba(255, 255, 255, 0.06);
  border-radius: 12px;
  padding: 16px;

  &:hover {
    background: rgba(255, 255, 255, 0.05);
  }

  &.unread {
    border-color: rgba(59, 130, 246, 0.3);
    background: rgba(59, 130, 246, 0.05);
  }
}

.latest-card.cyber-card {
  padding: 16px;
  border-radius: 12px;
}

.light .latest-card:not(.cyber-card) {
  background: rgba(0, 0, 0, 0.02);
  border-color: rgba(0, 0, 0, 0.06);

  &:hover {
    background: rgba(0, 0, 0, 0.04);
  }

  &.unread {
    border-color: rgba(59, 130, 246, 0.3);
    background: rgba(59, 130, 246, 0.03);
  }
}

.latest-header {
  display: flex;
  align-items: center;
  gap: 12px;
  margin-bottom: 12px;
}

.trigger {
  font-weight: 600;
  font-size: 15px;
  color: #e4e4e7;
  flex: 1;
}

.light .trigger {
  color: #27272a;
}

.level-badge,
.target-badge {
  display: inline-flex;
  align-items: center;
  padding: 2px 8px;
  border-radius: 4px;
  font-size: 11px;
  font-weight: 500;
  text-transform: uppercase;
}

.level-badge {
  &.world {
    background: rgba(239, 68, 68, 0.1);
    color: #ef4444;
  }

  &.regional {
    background: rgba(245, 158, 11, 0.1);
    color: #f59e0b;
  }
}

.target-badge {
  background: rgba(139, 92, 246, 0.1);
  color: #8b5cf6;
}

.new-badge {
  display: inline-flex;
  align-items: center;
  padding: 2px 8px;
  border-radius: 4px;
  font-size: 11px;
  font-weight: 600;
  background: #ef4444;
  color: white;
}

.scope {
  font-size: 13px;
  color: #a1a1aa;
  margin-bottom: 12px;
}

.light .scope {
  color: #71717a;
}

.changes-preview {
  font-size: 13px;
  color: #71717a;
  line-height: 1.5;
}

.changes {
  font-size: 14px;
  color: #e4e4e7;
  line-height: 1.6;
  white-space: pre-wrap;
}

.light .changes {
  color: #3f3f46;
}

.detail-content {
  margin-top: 12px;
  padding-top: 12px;
  border-top: 1px solid rgba(255, 255, 255, 0.06);
}

.light .detail-content {
  border-color: rgba(0, 0, 0, 0.06);
}

// ==================== Section Title ====================
.section-title {
  font-size: 12px;
  font-weight: 600;
  color: #71717a;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  margin-bottom: 12px;
  padding-left: 4px;
}

.light .section-title {
  color: #a1a1aa;
}

// ==================== Records List ====================
.records-list {
  display: flex;
  flex-direction: column;
  gap: 12px;
  margin-bottom: 24px;
}

.record-card {
  cursor: pointer;
  transition: all 0.2s;

  &.expanded {
    .record-detail {
      display: block;
    }
  }
}

.record-card:not(.cyber-card) {
  background: rgba(255, 255, 255, 0.02);
  border: 1px solid rgba(255, 255, 255, 0.04);
  border-radius: 8px;
  padding: 12px;

  &:hover {
    background: rgba(255, 255, 255, 0.04);
    border-color: rgba(255, 255, 255, 0.08);
  }

  &.unread {
    border-left: 3px solid #3b82f6;
  }
}

.record-card.cyber-card {
  padding: 12px;
  border-radius: 12px;

  &.unread {
    border-left: 3px solid var(--color-neon-cyan);
  }
}

.light .record-card:not(.cyber-card) {
  background: rgba(0, 0, 0, 0.01);
  border-color: rgba(0, 0, 0, 0.04);

  &:hover {
    background: rgba(0, 0, 0, 0.03);
    border-color: rgba(0, 0, 0, 0.08);
  }

  &.unread {
    border-left-color: #2563eb;
  }
}

.record-header {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 8px;
}

.time {
  font-size: 12px;
  color: #71717a;
  font-variant-numeric: tabular-nums;
}

.level-tag,
.target-tag {
  display: inline-flex;
  align-items: center;
  padding: 1px 6px;
  border-radius: 3px;
  font-size: 10px;
  font-weight: 500;
}

.level-tag {
  &.world {
    background: rgba(239, 68, 68, 0.1);
    color: #ef4444;
  }

  &.regional {
    background: rgba(245, 158, 11, 0.1);
    color: #f59e0b;
  }
}

.target-tag {
  background: rgba(139, 92, 246, 0.1);
  color: #8b5cf6;
}

.unread-dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: #3b82f6;
  margin-left: auto;
}

.record-detail {
  margin-top: 12px;
  padding-top: 12px;
  border-top: 1px solid rgba(255, 255, 255, 0.06);
}

.light .record-detail {
  border-color: rgba(0, 0, 0, 0.06);
}

// ==================== NPC Case Section ====================
.npc-case-section {
  margin-top: 16px;
  padding: 16px;
  border-radius: 12px;
}

.npc-case-section:not(.cyber-card) {
  background: rgba(245, 158, 11, 0.05);
  border: 1px solid rgba(245, 158, 11, 0.15);
}

.light .npc-case-section:not(.cyber-card) {
  background: rgba(245, 158, 11, 0.03);
}

.npc-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 12px;
}

.npc-title {
  display: flex;
  align-items: center;
  gap: 8px;
  font-weight: 600;
  color: #f59e0b;

  i {
    font-size: 14px;
  }
}

.refresh-btn {
  display: flex;
  align-items: center;
  gap: 4px;
  padding: 4px 10px;
  border-radius: 4px;
  font-size: 12px;
  cursor: pointer;
  transition: all 0.2s;
  border: none;
  background: rgba(255, 255, 255, 0.06);
  color: #a1a1aa;

  &:hover {
    background: rgba(255, 255, 255, 0.1);
    color: #e4e4e7;
  }
}

.light .refresh-btn {
  background: rgba(0, 0, 0, 0.05);
  color: #71717a;

  &:hover {
    background: rgba(0, 0, 0, 0.08);
    color: #27272a;
  }
}

.npc-content {
  display: flex;
  flex-direction: column;
  gap: 8px;
  font-size: 13px;
  color: #a1a1aa;
  line-height: 1.6;

  strong {
    color: #e4e4e7;
  }
}

.light .npc-content {
  color: #71717a;

  strong {
    color: #27272a;
  }
}

// ==================== Character Items (Personal Tab) ====================
.character-item {
  background: rgba(255, 255, 255, 0.03);
  border-radius: 8px;
  padding: 12px;
  margin-bottom: 8px;

  &:last-child {
    margin-bottom: 0;
  }
}

.light .character-item {
  background: rgba(0, 0, 0, 0.02);
}

.char-header {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 8px;
}

.char-name {
  font-weight: 500;
  color: #e4e4e7;
}

.light .char-name {
  color: #27272a;
}

.char-status {
  display: inline-flex;
  align-items: center;
  padding: 2px 8px;
  border-radius: 4px;
  font-size: 11px;

  &.inactive {
    background: rgba(107, 114, 128, 0.1);
    color: #6b7280;
  }

  &.retired {
    background: rgba(139, 92, 246, 0.1);
    color: #8b5cf6;
  }
}

.char-life {
  font-size: 13px;
  color: #a1a1aa;
  line-height: 1.5;
  margin-bottom: 4px;
}

.char-abnormal {
  font-size: 12px;
  color: #ef4444;
  line-height: 1.5;
}
