
.coord-tracker {
  position: fixed;
  bottom: 16px;
  right: 16px;
  font-family: 'Courier New', monospace;
  font-size: 10px;
  pointer-events: none;
  z-index: 100;
  display: flex;
  align-items: center;
  gap: 8px;
  letter-spacing: 0.1em;
}

.coord-label {
  color: rgba(168, 85, 247, 0.8);
}

.coord-value {
  color: rgba(6, 182, 212, 0.6);
  font-weight: bold;
  min-width: 40px;
}

.coord-separator {
  color: rgba(255, 255, 255, 0.3);
  margin: 0 4px;
}
