
.edit-cart-item-editor-overlay {
  position: fixed;
  inset: 0;
  z-index: 210000;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 16px;
  background: rgba(0, 0, 0, 0.6);
}

.edit-cart-item-editor-panel {
  width: 100%;
  max-width: 520px;
  max-height: min(85vh, 720px);
  display: flex;
  flex-direction: column;
  border-radius: 12px;
  border: 1px solid rgba(255, 255, 255, 0.12);
}

.edit-cart-item-editor-panel.dark {
  background: #18181b;
  color: #e4e4e7;
}

.edit-cart-item-editor-panel.light {
  background: #fafafa;
  color: #18181b;
  border-color: rgba(0, 0, 0, 0.1);
}

.eci-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 12px 14px;
  border-bottom: 1px solid rgba(255, 255, 255, 0.08);

  h3 {
    margin: 0;
    font-size: 16px;
  }
}

.light .eci-header {
  border-bottom-color: rgba(0, 0, 0, 0.08);
}

.eci-close {
  border: none;
  background: transparent;
  color: inherit;
  cursor: pointer;
  padding: 4px 8px;
  font-size: 18px;
  opacity: 0.85;

  &:hover {
    opacity: 1;
  }
}

.eci-body {
  padding: 12px 14px;
  overflow-y: auto;
  flex: 1;
  min-height: 0;
}

.eci-footer {
  display: flex;
  justify-content: flex-end;
  gap: 10px;
  padding: 12px 14px;
  border-top: 1px solid rgba(255, 255, 255, 0.08);
}

.light .eci-footer {
  border-top-color: rgba(0, 0, 0, 0.08);
}

.eci-label {
  display: block;
  font-size: 13px;
  font-weight: 500;
  margin: 10px 0 4px;
}

.eci-hint {
  font-size: 12px;
  opacity: 0.75;
  margin: 0 0 8px;
}

.eci-input,
.eci-textarea {
  width: 100%;
  box-sizing: border-box;
  padding: 8px 10px;
  border-radius: 8px;
  border: 1px solid rgba(255, 255, 255, 0.15);
  background: rgba(0, 0, 0, 0.25);
  color: inherit;
  font-size: 14px;
}

.light .eci-input,
.light .eci-textarea {
  border-color: rgba(0, 0, 0, 0.12);
  background: #fff;
}

.eci-textarea {
  resize: vertical;
  min-height: 80px;
}

.eci-btn {
  padding: 8px 16px;
  border-radius: 8px;
  font-size: 14px;
  cursor: pointer;
  border: none;

  &.secondary {
    background: transparent;
    border: 1px solid rgba(255, 255, 255, 0.2);
    color: inherit;
  }

  &.primary {
    background: #3b82f6;
    color: #fff;

    &:hover {
      background: #2563eb;
    }
  }
}

.light .eci-btn.secondary {
  border-color: rgba(0, 0, 0, 0.15);
}
