
.ecf {
  font-size: 14px;
}

.eci-label {
  display: block;
  font-size: 13px;
  font-weight: 500;
  margin: 10px 0 4px;
}

.eci-hint {
  font-size: 12px;
  opacity: 0.75;
  margin: 0 0 8px;
}

.eci-input,
.eci-textarea {
  width: 100%;
  box-sizing: border-box;
  padding: 8px 10px;
  border-radius: 8px;
  border: 1px solid rgba(255, 255, 255, 0.15);
  background: rgba(0, 0, 0, 0.25);
  color: inherit;
  font-size: 14px;
  margin-bottom: 4px;
}

.eci-textarea {
  resize: vertical;
}

.ecf-details {
  margin-top: 12px;
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 8px;
  padding: 8px;
}

.ecf-details summary {
  cursor: pointer;
  font-size: 13px;
  font-weight: 500;
}

.ecf-detail-block {
  margin-top: 10px;
  padding-top: 8px;
  border-top: 1px dashed rgba(255, 255, 255, 0.1);
}

.ecf-detail-row {
  display: flex;
  gap: 8px;
  align-items: center;
  margin-bottom: 8px;

  .eci-input {
    flex: 1;
  }
}

.ecf-jewelry-detail-row {
  flex-wrap: wrap;

  .eci-input {
    flex: 1 1 22%;
    min-width: 4.5rem;
  }
}

.ecf-icon-btn {
  flex-shrink: 0;
  padding: 6px 10px;
  border-radius: 6px;
  border: 1px solid rgba(239, 68, 68, 0.4);
  background: transparent;
  color: #f87171;
  cursor: pointer;
}

.ecf-add-btn {
  margin-top: 8px;
  padding: 6px 12px;
  font-size: 13px;
  border-radius: 6px;
  border: 1px solid rgba(59, 130, 246, 0.5);
  background: transparent;
  color: #60a5fa;
  cursor: pointer;
}
