
.random-rules-panel {
  padding: 16px;
  max-width: 800px;
  margin: 0 auto;
}

.panel-description {
  text-align: center;
  margin-bottom: 24px;

  .desc-text {
    font-size: 1.2em;
    font-weight: 600;
    margin-bottom: 8px;
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 8px;

    i {
      color: #8b5cf6;
    }
  }

  .desc-sub {
    font-size: 0.9em;
    opacity: 0.7;
  }
}

.dark .panel-description {
  color: #e2e8f0;
}

.light .panel-description {
  color: #475569;
}

.generate-section {
  text-align: center;
  margin-bottom: 32px;

  .generate-btn {
    padding: 12px 32px;
    font-size: 1.1em;
    font-weight: 600;
    border: none;
    border-radius: 8px;
    cursor: pointer;
    transition: all 0.3s ease;
    display: inline-flex;
    align-items: center;
    gap: 8px;
    background: linear-gradient(135deg, #8b5cf6, #7c3aed);
    color: white;

    &:hover:not(:disabled) {
      transform: translateY(-2px);
      box-shadow: 0 8px 20px rgba(139, 92, 246, 0.4);
    }

    &:disabled {
      opacity: 0.6;
      cursor: not-allowed;
    }
  }

  .generating-hint {
    margin-top: 12px;
    font-size: 0.9em;
    opacity: 0.7;
    animation: pulse 1.5s ease-in-out infinite;
  }
}

@keyframes pulse {
  0%, 100% { opacity: 0.7; }
  50% { opacity: 1; }
}

.results-section {
  .results-title {
    font-size: 1.3em;
    margin-bottom: 20px;
    display: flex;
    align-items: center;
    gap: 8px;

    i {
      color: #10b981;
    }
  }

  .rule-category {
    margin-bottom: 24px;

    .category-title {
      font-size: 1.1em;
      font-weight: 600;
      margin-bottom: 12px;
      padding-bottom: 8px;
      border-bottom: 2px solid;
      display: flex;
      align-items: center;
      gap: 8px;

      i {
        font-size: 0.9em;
      }
    }
  }
}

.dark .rule-category .category-title {
  border-color: #334155;
  color: #94a3b8;
}

.light .rule-category .category-title {
  border-color: #e2e8f0;
  color: #64748b;
}

.rule-card {
  padding: 16px;
  margin-bottom: 12px;
  transition: all 0.2s ease;
  width: 100%;
  max-width: 100%;
  box-sizing: border-box;
  min-width: 0;

  .rule-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 8px;

    .rule-target {
      font-size: 0.85em;
      font-weight: 600;
      padding: 2px 8px;
      border-radius: 4px;
      background: rgba(139, 92, 246, 0.2);
      color: #8b5cf6;
    }

    .rule-type {
      font-size: 0.75em;
      padding: 2px 6px;
      border-radius: 4px;
      text-transform: uppercase;
      font-weight: 700;

      &[data-type="personal"] {
        background: #3b82f6;
        color: white;
      }

      &[data-type="regional"] {
        background: #f59e0b;
        color: white;
      }

      &[data-type="world"] {
        background: #ef4444;
        color: white;
      }
    }
  }

  .rule-title {
    font-size: 1.1em;
    font-weight: 600;
    margin-bottom: 8px;
    max-width: 100%;
    word-break: break-word;
    overflow-wrap: anywhere;
    line-height: 1.35;
  }

  .rule-desc {
    font-size: 0.95em;
    line-height: 1.5;
    opacity: 0.85;
    margin-bottom: 12px;
    max-width: 100%;
    word-break: break-word;
    overflow-wrap: anywhere;
  }

  .rule-actions {
    display: flex;
    justify-content: flex-end;

    .btn-apply {
      padding: 6px 16px;
      font-size: 0.9em;
      border: none;
      border-radius: 6px;
      cursor: pointer;
      transition: all 0.2s ease;
      display: flex;
      align-items: center;
      gap: 6px;
      background: #10b981;
      color: white;

      &:hover:not(:disabled) {
        background: #059669;
        transform: scale(1.05);
      }

      &:disabled {
        background: #6b7280;
        cursor: default;
      }
    }
  }
}

.rule-card:not(.cyber-card) {
  border-radius: 8px;
  border: 1px solid;

  &:hover {
    transform: translateX(4px);
  }
}

.rule-card.cyber-card {
  border-radius: 12px;

  &:hover {
    transform: translateX(2px);
  }
}

.dark .rule-card:not(.cyber-card) {
  background: rgba(30, 41, 59, 0.6);
  border-color: #334155;

  .rule-title {
    color: #f1f5f9;
  }

  .rule-desc {
    color: #cbd5e1;
  }
}

.dark .rule-card.cyber-card {
  .rule-title {
    color: #f1f5f9;
  }

  .rule-desc {
    color: #cbd5e1;
  }
}

.light .rule-card:not(.cyber-card) {
  background: #f8fafc;
  border-color: #e2e8f0;

  .rule-title {
    color: #1e293b;
  }

  .rule-desc {
    color: #475569;
  }
}

.regenerate-section {
  text-align: center;
  margin-top: 24px;
  padding-top: 24px;
  border-top: 1px solid;

  .btn-secondary {
    padding: 8px 20px;
    font-size: 0.95em;
    border: 1px solid;
    border-radius: 6px;
    cursor: pointer;
    transition: all 0.2s ease;
    display: inline-flex;
    align-items: center;
    gap: 6px;

    &:hover:not(:disabled) {
      transform: scale(1.02);
    }

    &:disabled {
      opacity: 0.6;
      cursor: not-allowed;
    }
  }
}

.dark .regenerate-section {
  border-color: #334155;

  .btn-secondary {
    background: transparent;
    border-color: #475569;
    color: #94a3b8;

    &:hover:not(:disabled) {
      background: rgba(71, 85, 105, 0.3);
      color: #e2e8f0;
    }
  }
}

.light .regenerate-section {
  border-color: #e2e8f0;

  .btn-secondary {
    background: transparent;
    border-color: #cbd5e1;
    color: #64748b;

    &:hover:not(:disabled) {
      background: rgba(203, 213, 225, 0.3);
      color: #475569;
    }
  }
}

.error-message {
  padding: 16px;
  border-radius: 8px;
  text-align: center;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  margin-top: 16px;

  i {
    color: #ef4444;
  }
}

.dark .error-message {
  background: rgba(239, 68, 68, 0.1);
  color: #fca5a5;
}

.light .error-message {
  background: #fef2f2;
  color: #991b1b;
}

// 主题输入弹窗样式
.theme-dialog-overlay {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: rgba(0, 0, 0, 0.6);
  backdrop-filter: blur(4px);
  z-index: 1000;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 20px;
}

.theme-dialog-modal {
  width: 100%;
  max-width: 500px;
  border-radius: 12px;
  box-shadow: 0 20px 60px rgba(0, 0, 0, 0.3);
  overflow: hidden;
  animation: modalSlideIn 0.3s ease;
}

.theme-dialog-modal--wide {
  max-width: 560px;
}

@keyframes modalSlideIn {
  from {
    opacity: 0;
    transform: translateY(-20px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.dark .theme-dialog-modal {
  background: #1e293b;
}

.light .theme-dialog-modal {
  background: #ffffff;
}

.form-readonly-row {
  display: flex;
  align-items: baseline;
  gap: 12px;
  margin-bottom: 10px;
  font-size: 0.9em;

  .form-label {
    flex-shrink: 0;
    min-width: 4.5em;
    opacity: 0.75;
    font-weight: 500;
  }

  .form-readonly-value {
    flex: 1;
    word-break: break-word;
  }
}

.form-group {
  margin-bottom: 14px;

  .form-label {
    display: block;
    margin-bottom: 6px;
    font-size: 0.9em;
    font-weight: 500;
    opacity: 0.85;
  }
}

.dark .form-group .form-label,
.dark .form-readonly-row .form-label {
  color: #94a3b8;
}

.light .form-group .form-label,
.light .form-readonly-row .form-label {
  color: #64748b;
}

.dark .form-readonly-row .form-readonly-value {
  color: #e2e8f0;
}

.light .form-readonly-row .form-readonly-value {
  color: #334155;
}

.form-input,
.form-textarea {
  width: 100%;
  padding: 10px 12px;
  border-radius: 8px;
  border: 1px solid;
  font-size: 0.95em;
  font-family: inherit;
  box-sizing: border-box;

  &:focus {
    outline: none;
    border-color: #8b5cf6;
  }
}

.form-textarea {
  resize: vertical;
  min-height: 100px;
}

.dark .form-input,
.dark .form-textarea {
  background: #0f172a;
  border-color: #334155;
  color: #f1f5f9;

  &::placeholder {
    color: #475569;
  }
}

.light .form-input,
.light .form-textarea {
  background: #f8fafc;
  border-color: #cbd5e1;
  color: #1e293b;

  &::placeholder {
    color: #94a3b8;
  }
}

.apply-edit-hint {
  margin-top: 8px;
  margin-bottom: 0;
}

.theme-dialog-header {
  padding: 16px 20px;
  border-bottom: 1px solid;
  display: flex;
  justify-content: space-between;
  align-items: center;

  h2 {
    font-size: 1.2em;
    font-weight: 600;
    display: flex;
    align-items: center;
    gap: 8px;
    margin: 0;

    i {
      color: #f59e0b;
    }
  }

  .close-btn {
    background: none;
    border: none;
    font-size: 1.2em;
    cursor: pointer;
    padding: 4px;
    border-radius: 4px;
    transition: background 0.2s;

    &:hover {
      background: rgba(255, 255, 255, 0.1);
    }
  }
}

.dark .theme-dialog-header {
  border-color: #334155;
  color: #f1f5f9;

  .close-btn {
    color: #94a3b8;
  }
}

.light .theme-dialog-header {
  border-color: #e2e8f0;
  color: #1e293b;

  .close-btn {
    color: #64748b;
  }
}

.theme-dialog-body {
  padding: 20px;

  .theme-hint {
    font-size: 0.9em;
    opacity: 0.8;
    margin-bottom: 12px;
    line-height: 1.5;
  }

  .theme-textarea {
    width: 100%;
    padding: 12px;
    border-radius: 8px;
    border: 1px solid;
    font-size: 0.95em;
    font-family: inherit;
    resize: vertical;
    min-height: 80px;
    transition: border-color 0.2s;

    &:focus {
      outline: none;
      border-color: #8b5cf6;
    }
  }

  .theme-examples {
    margin-top: 12px;
    display: flex;
    flex-wrap: wrap;
    gap: 8px;

    .example-tag {
      padding: 4px 12px;
      font-size: 0.85em;
      border-radius: 16px;
      cursor: pointer;
      transition: all 0.2s;

      &:hover {
        transform: scale(1.05);
      }
    }
  }
}

.dark .theme-dialog-body {
  .theme-hint {
    color: #94a3b8;
  }

  .theme-textarea {
    background: #0f172a;
    border-color: #334155;
    color: #f1f5f9;

    &::placeholder {
      color: #475569;
    }
  }

  .example-tag {
    background: rgba(139, 92, 246, 0.2);
    color: #c4b5fd;
    border: 1px solid rgba(139, 92, 246, 0.3);

    &:hover {
      background: rgba(139, 92, 246, 0.3);
    }
  }
}

.light .theme-dialog-body {
  .theme-hint {
    color: #64748b;
  }

  .theme-textarea {
    background: #f8fafc;
    border-color: #cbd5e1;
    color: #1e293b;

    &::placeholder {
      color: #94a3b8;
    }
  }

  .example-tag {
    background: rgba(139, 92, 246, 0.1);
    color: #7c3aed;
    border: 1px solid rgba(139, 92, 246, 0.2);

    &:hover {
      background: rgba(139, 92, 246, 0.2);
    }
  }
}

.theme-dialog-actions {
  padding: 16px 20px;
  border-top: 1px solid;
  display: flex;
  justify-content: flex-end;
  gap: 12px;

  button {
    padding: 8px 20px;
    border-radius: 6px;
    font-size: 0.95em;
    cursor: pointer;
    transition: all 0.2s;
    display: flex;
    align-items: center;
    gap: 6px;

    &.btn-cancel {
      background: transparent;
      border: 1px solid;
    }

    &.btn-confirm {
      background: linear-gradient(135deg, #8b5cf6, #7c3aed);
      color: white;
      border: none;

      &:hover {
        transform: translateY(-1px);
        box-shadow: 0 4px 12px rgba(139, 92, 246, 0.4);
      }
    }
  }
}

.dark .theme-dialog-actions {
  border-color: #334155;

  .btn-cancel {
    color: #94a3b8;
    border-color: #475569;

    &:hover {
      background: rgba(71, 85, 105, 0.3);
    }
  }
}

.light .theme-dialog-actions {
  border-color: #e2e8f0;

  .btn-cancel {
    color: #64748b;
    border-color: #cbd5e1;

    &:hover {
      background: rgba(203, 213, 225, 0.3);
    }
  }
}

// 弹窗过渡动画
.modal-enter-active,
.modal-leave-active {
  transition: all 0.3s ease;
}

.modal-enter-from,
.modal-leave-to {
  opacity: 0;

  .theme-dialog-modal {
    transform: translateY(-20px);
  }
}
